-- Статті
INSERT INTO articles (title, slug, excerpt, content, cover_url, author_id, category_id, status, views, meta_title, meta_description, published_at) VALUES
('Server Components у React: що змінилось у 2026 році', 'react-server-components-2026', 'React Server Components остаточно стали стандартом. Розбираємо, як вони працюють, де дають виграш і яких помилок уникати.', '<p>React Server Components (RSC) пройшли довгий шлях від експериментальної ідеї до основи сучасних застосунків. Сьогодні вони визначають архітектуру більшості нових проєктів на Next.js.</p>
<h2>Чому це важливо</h2>
<p>Серверні компоненти виконуються на сервері та надсилають у браузер уже готовий результат. Це означає менший обсяг JavaScript на клієнті, швидше перше відображення та кращі показники Core Web Vitals.</p>
<p>Для SEO це принципово: пошуковий робот отримує повноцінний HTML одразу, без необхідності виконувати важкий клієнтський код.</p>
<h2>Коли використовувати клієнтські компоненти</h2>
<ul><li>Інтерактивні елементи зі станом (форми, модальні вікна).</li><li>Компоненти, що використовують браузерні API.</li><li>Обробники подій користувача.</li></ul>
<p>Усе інше варто залишати серверним за замовчуванням. Це проста, але потужна стратегія оптимізації.</p>', 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=1200&q=80', 1, 1, 'published', 2868, 'Server Components у React: що змінилось у 2026 році', 'React Server Components остаточно стали стандартом. Розбираємо, як вони працюють, де дають виграш і яких помилок уникати.', NOW() - INTERVAL '12 days'),
('Next.js App Router: повний гайд по стратегіях рендерингу', 'nextjs-app-router-rendering', 'SSG, SSR, ISR та CSR — коли який підхід обирати. Практичні приклади для реальних сторінок блогу.', '<p>App Router дав розробникам тонкий контроль над тим, як саме рендериться кожна сторінка. Розберемо чотири основні стратегії та коли яку обирати.</p>
<h2>SSG — статична генерація</h2>
<p>Сторінка будується під час збірки та віддається як готовий HTML. Ідеально для контенту, що змінюється рідко: головна сторінка, сторінки категорій.</p>
<h2>ISR — інкрементальна регенерація</h2>
<p>Компроміс між статикою та свіжістю даних. Сторінка кешується, але періодично оновлюється у фоні через параметр revalidate.</p>
<h2>SSR — рендеринг на запит</h2>
<p>Сторінка генерується на сервері для кожного запиту. Підходить для унікального контенту, де важлива актуальність, наприклад сторінка статті з лічильником переглядів.</p>
<h2>CSR — рендеринг на клієнті</h2>
<p>Дані завантажуються вже у браузері. Прийнятно для приватних сторінок без вимог до SEO: пошук, адмін-панель.</p>', 'https://images.unsplash.com/photo-1517180102446-f3ece451e9d8?w=1200&q=80', 1, 1, 'published', 1379, 'Next.js App Router: повний гайд по стратегіях рендерингу', 'SSG, SSR, ISR та CSR — коли який підхід обирати. Практичні приклади для реальних сторінок блогу.', NOW() - INTERVAL '11 days'),
('TypeScript 6: найважливіші нововведення', 'typescript-6-features', 'Покращений вивід типів, нові утиліти та пришвидшена компіляція. Огляд того, що дійсно змінить ваш щоденний код.', '<p>Нова версія TypeScript принесла відчутні покращення у виводі типів та швидкості компіляції великих проєктів.</p>
<h2>Швидша компіляція</h2>
<p>Команда переписала частину перевірки типів, що дало пришвидшення до 40% на великих кодових базах. Для монорепозиторіїв це справжній подарунок.</p>
<h2>Нові службові типи</h2>
<p>Зʼявились зручні утиліти для роботи зі звуженням типів, що дозволяє писати безпечніший код із меншою кількістю явних анотацій.</p>', 'https://images.unsplash.com/photo-1599507593499-a3f7d7d97667?w=1200&q=80', 1, 1, 'published', 887, 'TypeScript 6: найважливіші нововведення', 'Покращений вивід типів, нові утиліти та пришвидшена компіляція. Огляд того, що дійсно змінить ваш щоденний код.', NOW() - INTERVAL '10 days'),
('PostgreSQL для розробника: індекси, які реально працюють', 'postgresql-indexes-guide', 'B-tree, GIN, partial та covering індекси. Коли вони прискорюють запити, а коли лише сповільнюють запис.', '<p>Індекси — головний інструмент оптимізації запитів у PostgreSQL. Але неправильний індекс може зашкодити більше, ніж його відсутність.</p>
<h2>B-tree — універсальний вибір</h2>
<p>Стандартний тип індексу. Підходить для більшості випадків: пошук за рівністю, діапазони, сортування.</p>
<h2>GIN — для повнотекстового пошуку</h2>
<p>Якщо ви шукаєте всередині тексту або працюєте з JSONB, GIN-індекс значно прискорить запити.</p>
<h2>Ціна індексів</h2>
<p>Кожен індекс уповільнює операції вставки та оновлення, адже його теж потрібно підтримувати. Створюйте лише ті індекси, що відповідають реальним запитам вашого застосунку.</p>', 'https://images.unsplash.com/photo-1544383835-bda2bc66a55d?w=1200&q=80', 2, 2, 'published', 3957, 'PostgreSQL для розробника: індекси, які реально працюють', 'B-tree, GIN, partial та covering індекси. Коли вони прискорюють запити, а коли лише сповільнюють запис.', NOW() - INTERVAL '9 days'),
('Docker у 2026: мультистейдж-збірки та оптимізація образів', 'docker-multistage-builds', 'Як зменшити розмір Docker-образу в кілька разів за допомогою мультистейдж-збірок та правильного кешування шарів.', '<p>Великі Docker-образи — це повільні деплої та зайві витрати. Мультистейдж-збірки розвʼязують цю проблему елегантно.</p>
<h2>Ідея мультистейджу</h2>
<p>Ви використовуєте один образ для збірки застосунку, а в фінальний образ копіюєте лише готовий результат без інструментів збірки.</p>
<pre><code>FROM node:20 AS build
WORKDIR /app
COPY . .
RUN npm ci && npm run build

FROM node:20-slim
COPY --from=build /app/dist ./dist
CMD ["node", "dist/index.js"]</code></pre>
<p>Такий підхід легко зменшує образ із гігабайта до сотні мегабайтів.</p>', 'https://images.unsplash.com/photo-1605745341112-85968b19335b?w=1200&q=80', 2, 2, 'published', 269, 'Docker у 2026: мультистейдж-збірки та оптимізація образів', 'Як зменшити розмір Docker-образу в кілька разів за допомогою мультистейдж-збірок та правильного кешування шарів.', NOW() - INTERVAL '8 days'),
('CI/CD на Railway: автоматичний деплой за 10 хвилин', 'railway-cicd-deploy', 'Налаштовуємо безперервний деплой із GitHub на Railway. Кожен push у main автоматично оновлює застосунок.', '<p>Railway робить деплой простим: підключаєте репозиторій, і кожен push автоматично запускає нову збірку.</p>
<h2>Три сервіси в одному проєкті</h2>
<p>Типова архітектура блогу складається з трьох сервісів: frontend, backend та база даних PostgreSQL. Railway дозволяє тримати їх разом і звʼязувати через внутрішні змінні середовища.</p>
<h2>Змінні середовища</h2>
<p>Ніколи не зберігайте паролі та ключі в коді. Railway надає зручний інтерфейс для керування секретами, які підставляються у застосунок під час запуску.</p>', 'https://images.unsplash.com/photo-1667372393119-3d4c48d07fc9?w=1200&q=80', 2, 2, 'published', 766, 'CI/CD на Railway: автоматичний деплой за 10 хвилин', 'Налаштовуємо безперервний деплой із GitHub на Railway. Кожен push у main автоматично оновлює застосунок.', NOW() - INTERVAL '7 days'),
('Як працюють великі мовні моделі: пояснення без математики', 'how-llm-works', 'Токени, увага та передбачення наступного слова. Інтуїтивне пояснення того, як насправді працюють сучасні LLM.', '<p>Великі мовні моделі здаються магією, але в основі лежить проста ідея: передбачення наступного токена на основі попереднього контексту.</p>
<h2>Що таке токен</h2>
<p>Модель не бачить слів так, як ми. Текст розбивається на токени — фрагменти слів, які модель перетворює на числа.</p>
<h2>Механізм уваги</h2>
<p>Серце сучасних моделей — механізм уваги. Він дозволяє моделі зважувати, які частини контексту найважливіші для передбачення наступного токена.</p>
<h2>Чому моделі помиляються</h2>
<p>Модель не знає фактів — вона оцінює ймовірності. Саме тому вона може впевнено генерувати неправдиву інформацію. Це явище називають галюцинаціями.</p>', 'https://images.unsplash.com/photo-1677442136019-21780ecad995?w=1200&q=80', 3, 3, 'published', 464, 'Як працюють великі мовні моделі: пояснення без математики', 'Токени, увага та передбачення наступного слова. Інтуїтивне пояснення того, як насправді працюють сучасні LLM.', NOW() - INTERVAL '6 days'),
('RAG: як навчити ШІ відповідати на основі ваших документів', 'rag-explained', 'Retrieval-Augmented Generation поєднує пошук та генерацію. Розбираємо, чому це найпопулярніший підхід для корпоративних застосунків ШІ.', '<p>RAG (Retrieval-Augmented Generation) дозволяє моделі відповідати на основі ваших власних даних, не вимагаючи дороговартісного донавчання.</p>
<h2>Як це працює</h2>
<ul><li>Документи розбиваються на фрагменти та перетворюються на вектори.</li><li>Запит користувача теж перетворюється на вектор.</li><li>Система знаходить найбільш релевантні фрагменти та додає їх у контекст моделі.</li></ul>
<p>У результаті модель відповідає, спираючись на конкретні джерела, що значно зменшує кількість галюцинацій.</p>', 'https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=1200&q=80', 3, 3, 'published', 2976, 'RAG: як навчити ШІ відповідати на основі ваших документів', 'Retrieval-Augmented Generation поєднує пошук та генерацію. Розбираємо, чому це найпопулярніший підхід для корпоративних застосунків ШІ.', NOW() - INTERVAL '5 days'),
('Векторні бази даних: огляд та порівняння', 'vector-databases-comparison', 'pgvector, Pinecone, Qdrant, Weaviate. Який інструмент обрати для семантичного пошуку у вашому проєкті.', '<p>Зі зростанням популярності RAG векторні бази даних стали критичним компонентом інфраструктури ШІ.</p>
<h2>pgvector — почати просто</h2>
<p>Якщо ви вже використовуєте PostgreSQL, розширення pgvector дозволяє зберігати та шукати вектори без додаткової інфраструктури. Чудовий вибір для старту.</p>
<h2>Спеціалізовані рішення</h2>
<p>Pinecone, Qdrant та Weaviate пропонують вищу продуктивність на великих обсягах, але додають складності в експлуатації. Обирайте їх, коли pgvector вже не справляється.</p>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=1200&q=80', 3, 3, 'published', 2324, 'Векторні бази даних: огляд та порівняння', 'pgvector, Pinecone, Qdrant, Weaviate. Який інструмент обрати для семантичного пошуку у вашому проєкті.', NOW() - INTERVAL '4 days'),
('OWASP Top 10: найпоширеніші вразливості вебзастосунків', 'owasp-top-10-guide', 'Ін`єкції, зламана автентифікація, XSS. Огляд головних загроз і того, як захистити від них свій застосунок.', '<p>OWASP Top 10 — це список найкритичніших ризиків безпеки вебзастосунків, який оновлюється спільнотою фахівців.</p>
<h2>SQL-інʼєкції</h2>
<p>Класична вразливість, що виникає при підстановці даних користувача безпосередньо у SQL-запит. Захист простий: завжди використовуйте параметризовані запити.</p>
<h2>Зламана автентифікація</h2>
<p>Слабкі паролі, незахищені токени та відсутність обмеження спроб входу роблять застосунок легкою мішенню. JWT із коротким терміном дії та хешування паролів через bcrypt — обовʼязковий мінімум.</p>
<h2>XSS — міжсайтовий скриптинг</h2>
<p>Якщо ви вставляєте дані користувача у HTML без екранування, зловмисник може виконати свій скрипт у браузері жертви. Сучасні фреймворки екранують вивід за замовчуванням.</p>', 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=1200&q=80', 2, 4, 'published', 741, 'OWASP Top 10: найпоширеніші вразливості вебзастосунків', 'Ін`єкції, зламана автентифікація, XSS. Огляд головних загроз і того, як захистити від них свій застосунок.', NOW() - INTERVAL '3 days'),
('JWT проти сесій: що обрати для автентифікації', 'jwt-vs-sessions', 'Stateless-токени чи серверні сесії? Розбираємо переваги, недоліки та типові помилки кожного підходу.', '<p>Питання вибору між JWT та сесіями виникає майже в кожному проєкті. Правильна відповідь залежить від ваших вимог.</p>
<h2>JWT — stateless</h2>
<p>Токен містить всю інформацію всередині себе та підписаний сервером. Сервер не зберігає стан, що зручно для масштабування. Недолік: токен складно відкликати до завершення терміну дії.</p>
<h2>Сесії — stateful</h2>
<p>Сервер зберігає інформацію про сесію, а клієнт тримає лише ідентифікатор. Легко відкликати, але потребує спільного сховища сесій при горизонтальному масштабуванні.</p>', 'https://images.unsplash.com/photo-1614064641938-3bbee52942c7?w=1200&q=80', 2, 4, 'published', 3516, 'JWT проти сесій: що обрати для автентифікації', 'Stateless-токени чи серверні сесії? Розбираємо переваги, недоліки та типові помилки кожного підходу.', NOW() - INTERVAL '2 days'),
('VS Code чи Neovim: чесне порівняння у 2026', 'vscode-vs-neovim-2026', 'Зручність проти швидкості та контролю. Допомагаємо визначитись, який редактор підійде саме вам.', '<p>Війна редакторів триває вічно, але обидва інструменти у 2026 році сильніші, ніж будь-коли.</p>
<h2>VS Code — зручність із коробки</h2>
<p>Величезна екосистема розширень, чудова підтримка налагодження та інтеграція з ШІ-асистентами роблять його ідеальним для команд та новачків.</p>
<h2>Neovim — швидкість і контроль</h2>
<p>Після початкового навчання Neovim дає неперевершену швидкість редагування та повний контроль над конфігурацією. Вибір тих, хто проводить у редакторі весь день.</p>', 'https://images.unsplash.com/photo-1629654297299-c8506221ca97?w=1200&q=80', 1, 5, 'published', 2757, 'VS Code чи Neovim: чесне порівняння у 2026', 'Зручність проти швидкості та контролю. Допомагаємо визначитись, який редактор підійде саме вам.', NOW() - INTERVAL '1 days');

